    55вҶ’//----------------------------------------------------------------------------------------
    56вҶ’// \!fn void Mesh::LoadBalancingAndAdaptiveMeshRefinement(ParameterInput *pin)
    57вҶ’// \brief Main function for adaptive mesh refinement
    58вҶ’
    59вҶ’void Mesh::LoadBalancingAndAdaptiveMeshRefinement(int ncycles_over, ParameterInput *pin,
    60вҶ’                                                  ApplicationInput *app_in) {
    61вҶ’  Kokkos::Profiling::pushRegion("LoadBalancingAndAdaptiveMeshRefinement");
    62вҶ’
    63вҶ’  int bidx = 0;
    64вҶ’  for (auto &pmb : block_list) {
    65вҶ’    tau::LogBlockEvent(pmb->gid, TAU_BLKEVT_RANK_GID, bidx++);
    66вҶ’  }
    67вҶ’
    68вҶ’  int nnew = 0, ndel = 0;
    69вҶ’
    70вҶ’  if (adaptive) {
    71вҶ’    UpdateMeshBlockTree(nnew, ndel);
    72вҶ’    nbnew += nnew;
    73вҶ’    nbdel += ndel;
    74вҶ’  }
    75вҶ’
    76вҶ’  lb_flag_ |= lb_automatic_;
    77вҶ’
    78вҶ’  UpdateCostList();
    79вҶ’
    80вҶ’  modified = false;
    81вҶ’
    82вҶ’  // to force pack size == 1 in athena_pk
    83вҶ’  if (ncycles_over == 1) {
    84вҶ’    if (Globals::my_rank == 0) {
    85вҶ’      std::cout << "[ALERT] Changing pack size to 1. Prev: " << default_pack_size_
    86вҶ’                << std::endl;
    87вҶ’    }
    88вҶ’
    89вҶ’    default_pack_size_ = 1;
    90вҶ’    GatherCostListAndCheckBalance();
    91вҶ’    RedistributeAndRefineMeshBlocks(pin, app_in, nbtotal);
    92вҶ’    modified = true;
    93вҶ’  } else {
    94вҶ’    if (nnew != 0 || ndel != 0) { // at least one (de)refinement happened
    95вҶ’      GatherCostListAndCheckBalance();
    96вҶ’      RedistributeAndRefineMeshBlocks(pin, app_in, nbtotal + nnew - ndel);
    97вҶ’      modified = true;
    98вҶ’    } else if (lb_flag_ && step_since_lb >= lb_interval_) {
    99вҶ’      // if (!GatherCostListAndCheckBalance()) { // load imbalance detected
   100вҶ’      // XXX AJ: R&R completely at the interval
   101вҶ’      GatherCostListAndCheckBalance();
   102вҶ’      RedistributeAndRefineMeshBlocks(pin, app_in, nbtotal);
   103вҶ’      modified = true;
   104вҶ’      // }
   105вҶ’      lb_flag_ = false;
   106вҶ’    }
   107вҶ’  }
   108вҶ’
   109вҶ’  // gid = -1 denotes end of LBandAMR
   110вҶ’  tau::LogBlockEvent(-1, TAU_BLKEVT_FLAG_REF, 0);
   111вҶ’  Kokkos::Profiling::popRegion(); // LoadBalancingAndAdaptiveMeshRefinement
   112вҶ’}
   113вҶ’
   114вҶ’// Private routines
   115вҶ’namespace {
   116вҶ’/**
   117вҶ’ * @brief This routine assigns blocks to ranks by attempting to place index-contiguous
   118вҶ’ * blocks of equal total cost on each rank.
   119вҶ’ *
   120вҶ’ * @param costlist (Input) A map of global block ID to a relative weight.
   121вҶ’ * @param ranklist (Output) A map of global block ID to ranks.
   122вҶ’ */
   123вҶ’void AssignBlocks(std::vector<double> const &costlist, std::vector<int> &ranklist) {
   124вҶ’  ranklist.resize(costlist.size());
   125вҶ’
   126вҶ’  double const total_cost = std::accumulate(costlist.begin(), costlist.end(), 0.0);
   127вҶ’
   128вҶ’  int rank = (Globals::nranks)-1;
   129вҶ’  double target_cost = total_cost / Globals::nranks;
   130вҶ’  double my_cost = 0.0;
   131вҶ’  double remaining_cost = total_cost;
   132вҶ’  // create rank list from the end: the master MPI rank should have less load
   133вҶ’  for (int block_id = costlist.size() - 1; block_id >= 0; block_id--) {
   134вҶ’    if (target_cost == 0.0) {
   135вҶ’      std::stringstream msg;
   136вҶ’      msg << "### FATAL ERROR in CalculateLoadBalance" << std::endl
   137вҶ’          << "There is at least one process which has no MeshBlock" << std::endl
   138вҶ’          << "Decrease the number of processes or use smaller MeshBlocks." << std::endl;
   139вҶ’      PARTHENON_FAIL(msg);
   140вҶ’    }
   141вҶ’    my_cost += costlist[block_id];
   142вҶ’    ranklist[block_id] = rank;
   143вҶ’    if (my_cost >= target_cost && rank > 0) {
   144вҶ’      rank--;
   145вҶ’      remaining_cost -= my_cost;
   146вҶ’      my_cost = 0.0;
   147вҶ’      target_cost = remaining_cost / (rank + 1);
   148вҶ’    }
   149вҶ’  }
   150вҶ’}
   151вҶ’
   152вҶ’void UpdateBlockList(std::vector<int> const &ranklist,
   153вҶ’                     std::vector<std::vector<int>> &rblist, std::vector<int> &nblist) {
   154вҶ’  rblist.resize(Globals::nranks);
   155вҶ’  nblist.resize(Globals::nranks);
   156вҶ’
   157вҶ’  for (auto &v : rblist) {
   158вҶ’    v.clear();
   159вҶ’  }
   160вҶ’
   161вҶ’  std::fill(nblist.begin(), nblist.end(), 0);
   162вҶ’
   163вҶ’  for (int block_id = 0; block_id < ranklist.size(); block_id++) {
   164вҶ’    int rank = ranklist[block_id];
   165вҶ’    rblist[rank].push_back(block_id);
   166вҶ’    nblist[rank]++;
   167вҶ’  }
   168вҶ’}
   169вҶ’} // namespace
   170вҶ’
   171вҶ’//----------------------------------------------------------------------------------------
   172вҶ’// \brief Calculate distribution of MeshBlocks based on the cost list
   173вҶ’void Mesh::CalculateLoadBalance(std::vector<double> const &costlist,
   174вҶ’                                std::vector<int> &ranklist,
   175вҶ’                                std::vector<std::vector<int>> &rblist,
   176вҶ’                                std::vector<int> &nblist) {
   177вҶ’  Kokkos::Profiling::pushRegion("CalculateLoadBalance");
   178вҶ’  auto const total_blocks = costlist.size();
   179вҶ’
   180вҶ’  using it = std::vector<double>::const_iterator;
   181вҶ’  std::pair<it, it> const min_max = std::minmax_element(costlist.begin(), costlist.end());
   182вҶ’
   183вҶ’  double const mincost = min_max.first == costlist.begin() ? 0.0 : *min_max.first;
   184вҶ’  double const maxcost = min_max.second == costlist.begin() ? 0.0 : *min_max.second;
   185вҶ’
   186вҶ’  if (Globals::my_rank == 0) {
   187вҶ’    std::cout << "[LB] " << Globals::lb_policy << " being invoked!" << std::endl;
   188вҶ’  }
   189вҶ’
   190вҶ’  // Legacy direct calls lived here before the amr::lb wrapper existed. Keeping the
   191вҶ’  // block as documentation of the old behavior.
   192вҶ’  MPI_Comm comm = MPI_COMM_NULL;
   193вҶ’  if (Globals::nranks > 512) {
   194вҶ’    comm = MPI_COMM_WORLD;
   195вҶ’  }
   196вҶ’
   197вҶ’  amr::lb::PlacementArgs placement{Globals::lb_policy, costlist, ranklist,
   198вҶ’                                   Globals::nranks};
   199вҶ’  amr::lb::PlacementArgsMpi mpi_args{placement, Globals::my_rank, Globals::nranks,
   200вҶ’                                     comm};
   201вҶ’  (void)amr::lb::LoadBalance::AssignBlocksMpi(mpi_args);
   202вҶ’
   203вҶ’  // Updates nslist with the ID of the starting block on each rank and the count of blocks
   204вҶ’  // on each rank.
   205вҶ’  UpdateBlockList(ranklist, rblist, nblist);
   206вҶ’
   207вҶ’#ifdef MPI_PARALLEL
   208вҶ’  if (total_blocks % (Globals::nranks) != 0 && !adaptive && !lb_flag_ &&
   209вҶ’      maxcost == mincost && Globals::my_rank == 0) {
   210вҶ’    std::cout << "### Warning in CalculateLoadBalance" << std::endl
   211вҶ’              << "The number of MeshBlocks cannot be divided evenly. "
   212вҶ’              << "This will result in poor load balancing." << std::endl;
   213вҶ’  }
   214вҶ’#endif
   215вҶ’  if (Globals::nranks > total_blocks) {
   216вҶ’    if (!adaptive) {
   217вҶ’      // mesh is refined statically, treat this an as error (all ranks need to
   218вҶ’      // participate)
   219вҶ’      std::stringstream msg;
   220вҶ’      msg << "### FATAL ERROR in CalculateLoadBalance" << std::endl
   221вҶ’          << "There are fewer MeshBlocks than OpenMP threads on each MPI rank"
   222вҶ’          << std::endl
   223вҶ’          << "Decrease the number of threads or use more MeshBlocks." << std::endl;
   224вҶ’      PARTHENON_FAIL(msg);
   225вҶ’    } else if (Globals::my_rank == 0) {
   226вҶ’      // we have AMR, print warning only on Rank 0
   227вҶ’      std::cout << "### WARNING in CalculateLoadBalance" << std::endl
   228вҶ’                << "There are fewer MeshBlocks than OpenMP threads on each MPI rank"
   229вҶ’                << std::endl
   230вҶ’                << "This is likely fine if the number of meshblocks is expected to grow "
   231вҶ’                   "during the "
   232вҶ’                   "simulations. Otherwise, it might be worthwhile to decrease the "
   233вҶ’                   "number of threads or "
   234вҶ’                   "use more meshblocks."
   235вҶ’                << std::endl;
   236вҶ’    }
   237вҶ’  }
   238вҶ’  Kokkos::Profiling::popRegion(); // CalculateLoadBalance
   239вҶ’}
   240вҶ’
   241вҶ’//----------------------------------------------------------------------------------------
   242вҶ’// \!fn void Mesh::ResetLoadBalanceVariables()
   243вҶ’// \brief reset counters and flags for load balancing
   244вҶ’
   245вҶ’void Mesh::ResetLoadBalanceVariables() {
   246вҶ’  if (lb_automatic_) {
   247вҶ’    for (auto &pmb : block_list) {
   248вҶ’      costlist[pmb->gid] = TINY_NUMBER;
   249вҶ’      pmb->ResetTimeMeasurement();
   250вҶ’    }
   251вҶ’  } else if (lb_manual_) {
   252вҶ’    for (auto &pmb : block_list) {
   253вҶ’      costlist[pmb->gid] = TINY_NUMBER;
   254вҶ’      // pmb->ResetCostForLoadBalancing();
   255вҶ’    }
   256вҶ’  }
   257вҶ’  lb_flag_ = false;
   258вҶ’  step_since_lb = 0;
   259вҶ’}
   260вҶ’
   261вҶ’//----------------------------------------------------------------------------------------
   262вҶ’// \!fn void Mesh::UpdateCostList()
   263вҶ’// \brief update the cost list
   264вҶ’
   265вҶ’void Mesh::UpdateCostList() {
   266вҶ’  if (lb_automatic_) {
   267вҶ’    double w = static_cast<double>(lb_interval_ - 1) / static_cast<double>(lb_interval_);
   268вҶ’    for (auto &pmb : block_list) {
   269вҶ’      costlist[pmb->gid] = costlist[pmb->gid] * w + pmb->cost_;
   270вҶ’    }
   271вҶ’  } else if (lb_flag_) {
   272вҶ’    for (auto &pmb : block_list) {
   273вҶ’      costlist[pmb->gid] = pmb->cost_;
   274вҶ’      tau::LogBlockEvent(pmb->gid, TAU_BLKEVT_COST, pmb->cost_);
   275вҶ’    }
   276вҶ’  }
   277вҶ’}
   278вҶ’
   279вҶ’//----------------------------------------------------------------------------------------
   280вҶ’// \!fn void Mesh::UpdateMeshBlockTree(int &nnew, int &ndel)
   281вҶ’// \brief collect refinement flags and manipulate the MeshBlockTree
   282вҶ’
   283вҶ’void Mesh::UpdateMeshBlockTree(int &nnew, int &ndel) {
   284вҶ’  Kokkos::Profiling::pushRegion("UpdateMeshBlockTree");
   285вҶ’  // compute nleaf= number of leaf MeshBlocks per refined block
   286вҶ’  int nleaf = 2;
   287вҶ’  if (mesh_size.nx2 > 1) nleaf = 4;
   288вҶ’  if (mesh_size.nx3 > 1) nleaf = 8;
   289вҶ’
   290вҶ’  // collect refinement flags from all the meshblocks
   291вҶ’  // count the number of the blocks to be (de)refined
   292вҶ’  nref[Globals::my_rank] = 0;
   293вҶ’  nderef[Globals::my_rank] = 0;
   294вҶ’  for (auto const &pmb : block_list) {
   295вҶ’    if (pmb->pmr->refine_flag_ == 1) nref[Globals::my_rank]++;
   296вҶ’    if (pmb->pmr->refine_flag_ == -1) nderef[Globals::my_rank]++;
   297вҶ’  }
   298вҶ’#ifdef MPI_PARALLEL
   299вҶ’  PARTHENON_MPI_CHECK(
   300вҶ’      MPI_Allgather(MPI_IN_PLACE, 1, MPI_INT, nref.data(), 1, MPI_INT, MPI_COMM_WORLD));
   301вҶ’  PARTHENON_MPI_CHECK(
   302вҶ’      MPI_Allgather(MPI_IN_PLACE, 1, MPI_INT, nderef.data(), 1, MPI_INT, MPI_COMM_WORLD));
   303вҶ’#endif
   304вҶ’
   305вҶ’  // count the number of the blocks to be (de)refined and displacement
   306вҶ’  int tnref = 0, tnderef = 0;
   307вҶ’  for (int n = 0; n < Globals::nranks; n++) {
   308вҶ’    tnref += nref[n];
   309вҶ’    tnderef += nderef[n];
   310вҶ’  }
   311вҶ’  if (tnref == 0 && tnderef < nleaf) { // nothing to do
   312вҶ’    Kokkos::Profiling::popRegion();    // UpdateMeshBlockTree
   313вҶ’    return;
   314вҶ’  }
   315вҶ’
   316вҶ’  int rd = 0, dd = 0;
   317вҶ’  for (int n = 0; n < Globals::nranks; n++) {
   318вҶ’    rdisp[n] = rd;
   319вҶ’    ddisp[n] = dd;
   320вҶ’    // technically could overflow, since sizeof() operator returns
   321вҶ’    // std::size_t = long unsigned int > int
   322вҶ’    // on many platforms (LP64). However, these are used below in MPI calls for
   323вҶ’    // integer arguments (recvcounts, displs). MPI does not support > 64-bit count ranges
   324вҶ’    bnref[n] = static_cast<int>(nref[n] * sizeof(LogicalLocation));
   325вҶ’    bnderef[n] = static_cast<int>(nderef[n] * sizeof(LogicalLocation));
   326вҶ’    brdisp[n] = static_cast<int>(rd * sizeof(LogicalLocation));
   327вҶ’    bddisp[n] = static_cast<int>(dd * sizeof(LogicalLocation));
   328вҶ’    rd += nref[n];
   329вҶ’    dd += nderef[n];
   330вҶ’  }
   331вҶ’
   332вҶ’  // allocate memory for the location arrays
   333вҶ’  LogicalLocation *lref{}, *lderef{}, *clderef{};
   334вҶ’  if (tnref > 0) lref = new LogicalLocation[tnref];
   335вҶ’  if (tnderef >= nleaf) {
   336вҶ’    lderef = new LogicalLocation[tnderef];
   337вҶ’    clderef = new LogicalLocation[tnderef / nleaf];
   338вҶ’  }
   339вҶ’
   340вҶ’  // collect the locations and costs
   341вҶ’  int iref = rdisp[Globals::my_rank], ideref = ddisp[Globals::my_rank];
   342вҶ’  for (auto const &pmb : block_list) {
   343вҶ’    if (pmb->pmr->refine_flag_ == 1) lref[iref++] = pmb->loc;
   344вҶ’    if (pmb->pmr->refine_flag_ == -1 && tnderef >= nleaf) lderef[ideref++] = pmb->loc;
   345вҶ’  }
   346вҶ’#ifdef MPI_PARALLEL
   347вҶ’  if (tnref > 0) {
   348вҶ’    PARTHENON_MPI_CHECK(MPI_Allgatherv(MPI_IN_PLACE, bnref[Globals::my_rank], MPI_BYTE,
   349вҶ’                                       lref, bnref.data(), brdisp.data(), MPI_BYTE,
   350вҶ’                                       MPI_COMM_WORLD));
   351вҶ’  }
   352вҶ’  if (tnderef >= nleaf) {
   353вҶ’    PARTHENON_MPI_CHECK(MPI_Allgatherv(MPI_IN_PLACE, bnderef[Globals::my_rank], MPI_BYTE,
   354вҶ’                                       lderef, bnderef.data(), bddisp.data(), MPI_BYTE,
   355вҶ’                                       MPI_COMM_WORLD));
   356вҶ’  }
   357вҶ’#endif
   358вҶ’
   359вҶ’  if (lref) {
   360вҶ’    std::sort(lref, lref + tnref, LogicalLocation::SortComparator);
   361вҶ’  }
   362вҶ’
   363вҶ’  if (lderef) {
   364вҶ’    std::sort(lderef, lderef + tnderef, LogicalLocation::SortComparator);
   365вҶ’  }
   366вҶ’
   367вҶ’  // calculate the list of the newly derefined blocks
   368вҶ’  int ctnd = 0;
   369вҶ’  if (tnderef >= nleaf) {
   370вҶ’    int lk = 0, lj = 0;
   371вҶ’    if (mesh_size.nx2 > 1) lj = 1;
   372вҶ’    if (mesh_size.nx3 > 1) lk = 1;
   373вҶ’    for (int n = 0; n < tnderef; n++) {
   374вҶ’      if ((lderef[n].lx1 & 1LL) == 0LL && (lderef[n].lx2 & 1LL) == 0LL &&
   375вҶ’          (lderef[n].lx3 & 1LL) == 0LL) {
   376вҶ’        int r = n, rr = 0;
   377вҶ’        for (std::int64_t k = 0; k <= lk; k++) {
   378вҶ’          for (std::int64_t j = 0; j <= lj; j++) {
   379вҶ’            for (std::int64_t i = 0; i <= 1; i++) {
   380вҶ’              if (r < tnderef) {
   381вҶ’                if ((lderef[n].lx1 + i) == lderef[r].lx1 &&
   382вҶ’                    (lderef[n].lx2 + j) == lderef[r].lx2 &&
   383вҶ’                    (lderef[n].lx3 + k) == lderef[r].lx3 &&
   384вҶ’                    lderef[n].level == lderef[r].level)
   385вҶ’                  rr++;
   386вҶ’                r++;
   387вҶ’              }
   388вҶ’            }
   389вҶ’          }
   390вҶ’        }
   391вҶ’        if (rr == nleaf) {
   392вҶ’          clderef[ctnd].lx1 = lderef[n].lx1 >> 1;
   393вҶ’          clderef[ctnd].lx2 = lderef[n].lx2 >> 1;
   394вҶ’          clderef[ctnd].lx3 = lderef[n].lx3 >> 1;
   395вҶ’          clderef[ctnd].level = lderef[n].level - 1;
   396вҶ’          ctnd++;
   397вҶ’        }
   398вҶ’      }
   399вҶ’    }
   400вҶ’  }
   401вҶ’  // sort the lists by level
   402вҶ’  if (ctnd > 1) std::sort(clderef, &(clderef[ctnd - 1]), LogicalLocation::Greater);
   403вҶ’
   404вҶ’  if (tnderef >= nleaf) delete[] lderef;
   405вҶ’
   406вҶ’  // Now the lists of the blocks to be refined and derefined are completed
   407вҶ’  // Start tree manipulation
   408вҶ’  // Step 1. perform refinement
   409вҶ’  for (int n = 0; n < tnref; n++) {
   410вҶ’    MeshBlockTree *bt = tree.FindMeshBlock(lref[n]);
   411вҶ’    bt->Refine(nnew);
   412вҶ’  }
   413вҶ’  if (tnref != 0) delete[] lref;
   414вҶ’
   415вҶ’  // Step 2. perform derefinement
   416вҶ’  for (int n = 0; n < ctnd; n++) {
   417вҶ’    MeshBlockTree *bt = tree.FindMeshBlock(clderef[n]);
   418вҶ’    bt->Derefine(ndel);
   419вҶ’  }
   420вҶ’  if (tnderef >= nleaf) delete[] clderef;
   421вҶ’
   422вҶ’  Kokkos::Profiling::popRegion(); // UpdateMeshBlockTree
   423вҶ’}
   424вҶ’
   425вҶ’//----------------------------------------------------------------------------------------
   426вҶ’// \!fn bool Mesh::GatherCostListAndCheckBalance()
   427вҶ’// \brief collect the cost from MeshBlocks and check the load balance
   428вҶ’
   429вҶ’bool Mesh::GatherCostListAndCheckBalance() {
   430вҶ’  if (lb_manual_ || lb_automatic_) {
   431вҶ’    // local data structure, start offsets for costlist_ro
   432вҶ’    int nslist_loc[Globals::nranks];
   433вҶ’    // temporary costlist, rank ordered. global costlist is gid-ordered
   434вҶ’    double costlist_loc[nbtotal];
   435вҶ’
   436вҶ’    // Setup nslist
   437вҶ’    nslist_loc[0] = 0;
   438вҶ’    for (int ridx = 1; ridx < Globals::nranks; ridx++) {
   439вҶ’      nslist_loc[ridx] = nslist_loc[ridx - 1] + nblist[ridx - 1];
   440вҶ’    }
   441вҶ’
   442вҶ’    // Setup costlist_ro from Mesh::costlist
   443вҶ’    int nblocal = nblist[Globals::my_rank];
   444вҶ’    int nbs = nslist_loc[Globals::my_rank];
   445вҶ’
   446вҶ’    const std::vector<int> &myrblist = rblist[Globals::my_rank];
   447вҶ’
   448вҶ’    for (int bidx = 0; bidx < nblocal; bidx++) {
   449вҶ’      int bid = myrblist[bidx];
   450вҶ’      costlist_loc[nbs + bidx] = costlist[bid];
   451вҶ’    }
   452вҶ’
   453вҶ’#ifdef MPI_PARALLEL
   454вҶ’    PARTHENON_MPI_CHECK(MPI_Allgatherv(MPI_IN_PLACE, nblist[Globals::my_rank], MPI_DOUBLE,
   455вҶ’                                       costlist_loc, nblist.data(), nslist_loc,
   456вҶ’                                       MPI_DOUBLE, MPI_COMM_WORLD));
   457вҶ’#endif
   458вҶ’    double maxcost = 0.0, avecost = 0.0;
   459вҶ’    double mincost = 1e100;
   460вҶ’    for (int rank = 0; rank < Globals::nranks; rank++) {
   461вҶ’      double rcost = 0.0;
   462вҶ’      int ns = nslist_loc[rank];
   463вҶ’      int ne = ns + nblist[rank];
   464вҶ’      for (int n = ns; n < ne; ++n)
   465вҶ’        rcost += costlist_loc[n];
   466вҶ’      maxcost = std::max(maxcost, rcost);
   467вҶ’      avecost += rcost;
   468вҶ’      mincost = std::min(mincost, rcost);
   469вҶ’    }
   470вҶ’    avecost /= Globals::nranks;
   471вҶ’
   472вҶ’    if (Globals::my_rank == 0) {
   473вҶ’      fprintf(stdout, "[LB] Max: %.1f Avg: %.1f Min: %.1f\n", maxcost / 1e6,
   474вҶ’              avecost / 1e6, mincost / 1e6);
   475вҶ’    }
   476вҶ’
   477вҶ’    // Copy costlist_ro back to Mesh::costlist
   478вҶ’    // Currently copying the full costlist.
   479вҶ’    // Possible that only inner loop for ridx == Global::my_rank is needed
   480вҶ’
   481вҶ’    for (int ridx = 0; ridx < Globals::nranks; ridx++) {
   482вҶ’      int nsrank = nslist_loc[ridx];
   483вҶ’      for (int bidx = 0; bidx < nblist[ridx]; bidx++) {
   484вҶ’        int bid = rblist[ridx][bidx];
   485вҶ’        costlist[bid] = costlist_loc[nsrank + bidx];
   486вҶ’      }
   487вҶ’    }
   488вҶ’
   489вҶ’    if (adaptive)
   490вҶ’      lb_tolerance_ =
   491вҶ’          2.0 * static_cast<double>(Globals::nranks) / static_cast<double>(nbtotal);
   492вҶ’
   493вҶ’    if (maxcost > (1.0 + lb_tolerance_) * avecost) return false;
   494вҶ’  }
   495вҶ’  return true;
   496вҶ’}
