   499вҶ’// \!fn void Mesh::RedistributeAndRefineMeshBlocks(ParameterInput *pin, int ntot)
   500вҶ’// \brief redistribute MeshBlocks according to the new load balance
   501вҶ’
   502вҶ’void Mesh::RedistributeAndRefineMeshBlocks(ParameterInput *pin, ApplicationInput *app_in,
   503вҶ’                                           int ntot) {
   504вҶ’  auto _ts_beg = tau::GetUsSince(0);
   505вҶ’
   506вҶ’  Kokkos::Profiling::pushRegion("RedistributeAndRefineMeshBlocks");
   507вҶ’  // kill any cached packs
   508вҶ’  mesh_data.PurgeNonBase();
   509вҶ’  mesh_data.Get()->ClearCaches();
   510вҶ’
   511вҶ’  // compute nleaf= number of leaf MeshBlocks per refined block
   512вҶ’  int nleaf = 2;
   513вҶ’  if (mesh_size.nx2 > 1) nleaf = 4;
   514вҶ’  if (mesh_size.nx3 > 1) nleaf = 8;
   515вҶ’
   516вҶ’  // Step 1. construct new lists
   517вҶ’  Kokkos::Profiling::pushRegion("Step1: Construct new list");
   518вҶ’  std::vector<LogicalLocation> newloc(ntot);
   519вҶ’  std::vector<int> newrank(ntot);
   520вҶ’  std::vector<double> newcost(ntot);
   521вҶ’  std::vector<int> newtoold(ntot);
   522вҶ’  std::vector<int> oldtonew(nbtotal);
   523вҶ’
   524вҶ’  int nbtold = nbtotal;
   525вҶ’  tree.GetMeshBlockList(newloc.data(), newtoold.data(), nbtotal);
   526вҶ’
   527вҶ’  // create a list mapping the previous gid to the current one
   528вҶ’  oldtonew[0] = 0;
   529вҶ’  int mb_idx = 1;
   530вҶ’  for (int n = 1; n < ntot; n++) {
   531вҶ’    if (newtoold[n] == newtoold[n - 1] + 1) { // normal
   532вҶ’      oldtonew[mb_idx++] = n;
   533вҶ’    } else if (newtoold[n] == newtoold[n - 1] + nleaf) { // derefined
   534вҶ’      for (int j = 0; j < nleaf - 1; j++)
   535вҶ’        oldtonew[mb_idx++] = n - 1;
   536вҶ’      oldtonew[mb_idx++] = n;
   537вҶ’    }
   538вҶ’  }
   539вҶ’  // fill the last block
   540вҶ’  for (; mb_idx < nbtold; mb_idx++)
   541вҶ’    oldtonew[mb_idx] = ntot - 1;
   542вҶ’
   543вҶ’  current_level = 0;
   544вҶ’  for (int n = 0; n < ntot; n++) {
   545вҶ’    // "on" = "old n" = "old gid" = "old global MeshBlock ID"
   546вҶ’    int on = newtoold[n];
   547вҶ’    if (newloc[n].level > current_level) // set the current max level
   548вҶ’      current_level = newloc[n].level;
   549вҶ’    if (newloc[n].level >= loclist[on].level) { // same or refined
   550вҶ’      newcost[n] = costlist[on];
   551вҶ’    } else {
   552вҶ’      double acost = 0.0;
   553вҶ’      for (int l = 0; l < nleaf; l++)
   554вҶ’        acost += costlist[on + l];
   555вҶ’      newcost[n] = acost / nleaf;
   556вҶ’    }
   557вҶ’  }
   558вҶ’#ifdef MPI_PARALLEL
   559вҶ’  // store old nbstart and nbend before load balancing in Step 2.
   560вҶ’  std::vector<int> omyrblist(nblist[Globals::my_rank]);
   561вҶ’  std::copy(rblist[Globals::my_rank].begin(), rblist[Globals::my_rank].end(),
   562вҶ’            omyrblist.begin());
   563вҶ’#endif
   564вҶ’  Kokkos::Profiling::popRegion(); // Step 1
   565вҶ’
   566вҶ’  // Step 2. Calculate new load balance
   567вҶ’  CalculateLoadBalance(newcost, newrank, rblist, nblist);
   568вҶ’
   569вҶ’  std::vector<int> &nmyrblist = rblist[Globals::my_rank];
   570вҶ’
   571вҶ’#ifdef MPI_PARALLEL
   572вҶ’  int bnx1 = GetBlockSize().nx1;
   573вҶ’  int bnx2 = GetBlockSize().nx2;
   574вҶ’  int bnx3 = GetBlockSize().nx3;
   575вҶ’  // Step 3. count the number of the blocks to be sent / received
   576вҶ’  Kokkos::Profiling::pushRegion("Step 3: Count blocks");
   577вҶ’  int nsend = 0, nrecv = 0;
   578вҶ’  for (int n : nmyrblist) {
   579вҶ’    int on = newtoold[n];
   580вҶ’    if (loclist[on].level > newloc[n].level) { // f2c
   581вҶ’      for (int k = 0; k < nleaf; k++) {
   582вҶ’        if (ranklist[on + k] != Globals::my_rank) nrecv++;
   583вҶ’      }
   584вҶ’    } else {
   585вҶ’      if (ranklist[on] != Globals::my_rank) nrecv++;
   586вҶ’    }
   587вҶ’  }
   588вҶ’  for (int n : omyrblist) {
   589вҶ’    int nn = oldtonew[n];
   590вҶ’    if (loclist[n].level < newloc[nn].level) { // c2f
   591вҶ’      for (int k = 0; k < nleaf; k++) {
   592вҶ’        if (newrank[nn + k] != Globals::my_rank) nsend++;
   593вҶ’      }
   594вҶ’    } else {
   595вҶ’      if (newrank[nn] != Globals::my_rank) nsend++;
   596вҶ’    }
   597вҶ’  }
   598вҶ’
   599вҶ’  Kokkos::Profiling::popRegion(); // Step 3
   600вҶ’  // Step 4. calculate buffer sizes
   601вҶ’  Kokkos::Profiling::pushRegion("Step 4: Calc buffer sizes");
   602вҶ’  BufArray1D<Real> *sendbuf, *recvbuf;
   603вҶ’  // use the first MeshBlock in the linked list of blocks belonging to this MPI rank as a
   604вҶ’  // representative of all MeshBlocks for counting the "load-balancing registered" and
   605вҶ’  // "SMR/AMR-enrolled" quantities (loop over MeshBlock::vars_cc_, not MeshRefinement)
   606вҶ’
   607вҶ’  // TODO(felker): add explicit check to ensure that elements of pb->vars_cc/fc_ and
   608вҶ’  // pb->pmr->pvars_cc/fc_ v point to the same objects, if adaptive
   609вҶ’
   610вҶ’  // TODO(JL) Why are we using all variables for same-level but only the variables in pmr
   611вҶ’  // for c2f and f2c?s
   612вҶ’  int num_cc = block_list.front()->vars_cc_.size();
   613вҶ’  int num_pmr_cc = block_list.front()->pmr->pvars_cc_.size();
   614вҶ’  int nx4_tot = 0;
   615вҶ’  for (auto &pvar_cc : block_list.front()->vars_cc_) {
   616вҶ’    nx4_tot += pvar_cc->GetDim(4);
   617вҶ’  }
   618вҶ’
   619вҶ’  const int f2 = (ndim >= 2) ? 1 : 0; // extra cells/faces from being 2d
   620вҶ’  const int f3 = (ndim >= 3) ? 1 : 0; // extra cells/faces from being 3d
   621вҶ’
   622вҶ’  // cell-centered quantities enrolled in SMR/AMR
   623вҶ’  // TODO(JMM): I think this needs to be re-written to compute total
   624вҶ’  // size accross vars by looping over vars and getting their total
   625вҶ’  // size.
   626вҶ’  int bssame = bnx1 * bnx2 * bnx3 * nx4_tot;
   627вҶ’  int bsf2c = (bnx1 / 2) * ((bnx2 + 1) / 2) * ((bnx3 + 1) / 2) * nx4_tot;
   628вҶ’  int bsc2f =
   629вҶ’      (bnx1 / 2 + 2) * ((bnx2 + 1) / 2 + 2 * f2) * ((bnx3 + 1) / 2 + 2 * f3) * nx4_tot;
   630вҶ’
   631вҶ’  // add num_cc/num_pmr_cc to all buffer sizes for storing allocation statuses
   632вҶ’  bssame += num_cc;
   633вҶ’  bsc2f += num_pmr_cc;
   634вҶ’  bsf2c += num_pmr_cc;
   635вҶ’
   636вҶ’  // add one more element to buffer size for storing the derefinement counter
   637вҶ’  bssame++;
   638вҶ’  Kokkos::Profiling::popRegion(); // Step 4
   639вҶ’
   640вҶ’  MPI_Request *req_send, *req_recv;
   641вҶ’
   642вҶ’  // Step 5. Allocate space for send and recieve buffers
   643вҶ’  Kokkos::Profiling::pushRegion("Step 5: Allocate send and recv buf");
   644вҶ’  size_t buf_size = 0;
   645вҶ’  if (nrecv != 0) {
   646вҶ’    recvbuf = new BufArray1D<Real>[nrecv];
   647вҶ’    for (int n : nmyrblist) {
   648вҶ’      int on = newtoold[n];
   649вҶ’      LogicalLocation &oloc = loclist[on];
   650вҶ’      LogicalLocation &nloc = newloc[n];
   651вҶ’      if (oloc.level > nloc.level) { // f2c
   652вҶ’        for (int l = 0; l < nleaf; l++) {
   653вҶ’          if (ranklist[on + l] == Globals::my_rank) continue;
   654вҶ’          buf_size += bsf2c;
   655вҶ’        }
   656вҶ’      } else { // same level or c2f
   657вҶ’        if (ranklist[on] == Globals::my_rank) continue;
   658вҶ’        int size;
   659вҶ’        if (oloc.level == nloc.level) {
   660вҶ’          size = bssame;
   661вҶ’        } else {
   662вҶ’          size = bsc2f;
   663вҶ’        }
   664вҶ’        buf_size += size;
   665вҶ’      }
   666вҶ’    }
   667вҶ’  }
   668вҶ’  if (nsend != 0) {
   669вҶ’    sendbuf = new BufArray1D<Real>[nsend];
   670вҶ’    for (int n : omyrblist) {
   671вҶ’      int nn = oldtonew[n];
   672вҶ’      LogicalLocation &oloc = loclist[n];
   673вҶ’      LogicalLocation &nloc = newloc[nn];
   674вҶ’      auto pb = FindMeshBlock(n);
   675вҶ’      if (nloc.level == oloc.level) { // same level
   676вҶ’        if (newrank[nn] == Globals::my_rank) continue;
   677вҶ’        buf_size += bssame;
   678вҶ’      } else if (nloc.level > oloc.level) { // c2f
   679вҶ’        // c2f must communicate to multiple leaf blocks (unlike f2c, same2same)
   680вҶ’        for (int l = 0; l < nleaf; l++) {
   681вҶ’          if (newrank[nn + l] == Globals::my_rank) continue;
   682вҶ’          buf_size += bsc2f;
   683вҶ’        } // end loop over nleaf (unique to c2f branch in this step 6)
   684вҶ’      } else { // f2c: restrict + pack + send
   685вҶ’        if (newrank[nn] == Globals::my_rank) continue;
   686вҶ’        buf_size += bsf2c;
   687вҶ’      }
   688вҶ’    }
   689вҶ’  }
   690вҶ’  BufArray1D<Real> bufs("RedistributeAndRefineMeshBlocks sendrecv bufs", buf_size);
   691вҶ’  Kokkos::Profiling::popRegion(); // Step 5
   692вҶ’
   693вҶ’  // Step 6. allocate and start receiving buffers
   694вҶ’  Kokkos::Profiling::pushRegion("Step 6: Pack buffer and start recv");
   695вҶ’  size_t buf_offset = 0;
   696вҶ’  if (nrecv != 0) {
   697вҶ’    req_recv = new MPI_Request[nrecv];
   698вҶ’    int rb_idx = 0; // recv buffer index
   699вҶ’    for (int nidx = 0; nidx < nmyrblist.size(); nidx++) {
   700вҶ’      int n = nmyrblist[nidx];
   701вҶ’      int on = newtoold[n];
   702вҶ’      LogicalLocation &oloc = loclist[on];
   703вҶ’      LogicalLocation &nloc = newloc[n];
   704вҶ’      if (oloc.level > nloc.level) { // f2c
   705вҶ’        for (int l = 0; l < nleaf; l++) {
   706вҶ’          if (ranklist[on + l] == Globals::my_rank) continue;
   707вҶ’          LogicalLocation &lloc = loclist[on + l];
   708вҶ’          int ox1 = ((lloc.lx1 & 1LL) == 1LL), ox2 = ((lloc.lx2 & 1LL) == 1LL),
   709вҶ’              ox3 = ((lloc.lx3 & 1LL) == 1LL);
   710вҶ’          recvbuf[rb_idx] =
   711вҶ’              BufArray1D<Real>(bufs, std::make_pair(buf_offset, buf_offset + bsf2c));
   712вҶ’          buf_offset += bsf2c;
   713вҶ’          int tag = CreateAMRMPITag(nidx, ox1, ox2, ox3);
   714вҶ’          PARTHENON_MPI_CHECK(MPI_Irecv(recvbuf[rb_idx].data(), bsf2c, MPI_PARTHENON_REAL,
   715вҶ’                                        ranklist[on + l], tag, MPI_COMM_WORLD,
   716вҶ’                                        &(req_recv[rb_idx])));
   717вҶ’          rb_idx++;
   718вҶ’        }
   719вҶ’      } else { // same level or c2f
   720вҶ’        if (ranklist[on] == Globals::my_rank) continue;
   721вҶ’        int size;
   722вҶ’        if (oloc.level == nloc.level) {
   723вҶ’          size = bssame;
   724вҶ’        } else {
   725вҶ’          size = bsc2f;
   726вҶ’        }
   727вҶ’        recvbuf[rb_idx] =
   728вҶ’            BufArray1D<Real>(bufs, std::make_pair(buf_offset, buf_offset + size));
   729вҶ’        buf_offset += size;
   730вҶ’        int tag = CreateAMRMPITag(nidx, 0, 0, 0);
   731вҶ’        PARTHENON_MPI_CHECK(MPI_Irecv(recvbuf[rb_idx].data(), size, MPI_PARTHENON_REAL,
   732вҶ’                                      ranklist[on], tag, MPI_COMM_WORLD,
   733вҶ’                                      &(req_recv[rb_idx])));
   734вҶ’        rb_idx++;
   735вҶ’      }
   736вҶ’    }
   737вҶ’  }
   738вҶ’  Kokkos::Profiling::popRegion(); // Step 6
   739вҶ’
   740вҶ’  // Step 7. allocate, pack and start sending buffers
   741вҶ’  Kokkos::Profiling::pushRegion("Step 7: Pack and send buffers");
   742вҶ’  // if (Globals::timestep > 100) perf.Resume();
   743вҶ’
   744вҶ’  if (nsend != 0) {
   745вҶ’    Kokkos::Profiling::pushRegion("Step 7a: Pack buffers");
   746вҶ’
   747вҶ’    req_send = new MPI_Request[nsend];
   748вҶ’    std::vector<int> tags(nsend);
   749вҶ’    std::vector<int> dest(nsend);
   750вҶ’    std::vector<int> count(nsend);
   751вҶ’    int sb_idx = 0; // send buffer index
   752вҶ’    for (int nidx = 0; nidx < omyrblist.size(); nidx++) {
   753вҶ’      int n = omyrblist[nidx];
   754вҶ’      int nn = oldtonew[n];
   755вҶ’      LogicalLocation &oloc = loclist[n];
   756вҶ’      LogicalLocation &nloc = newloc[nn];
