   761вҶ’            BufArray1D<Real>(bufs, std::make_pair(buf_offset, buf_offset + bssame));
   762вҶ’        buf_offset += bssame;
   763вҶ’        PrepareSendSameLevel(pb.get(), sendbuf[sb_idx]);
