   775вҶ’          buf_offset += bsc2f;
   776вҶ’          PrepareSendCoarseToFineAMR(pb.get(), sendbuf[sb_idx], newloc[nn + l]);
   777вҶ’          int nnl_lid = GetLid(rblist, newrank, nn + l);
   778вҶ’          tags[sb_idx] = CreateAMRMPITag(nnl_lid, 0, 0, 0);
   779вҶ’          dest[sb_idx] = newrank[nn + l];
   780вҶ’          count[sb_idx] = bsc2f;
   781вҶ’          sb_idx++;
   782вҶ’        } // end loop over nleaf (unique to c2f branch in this step 6)
   783вҶ’      } else { // f2c: restrict + pack + send
   784вҶ’        if (newrank[nn] == Globals::my_rank) continue;
   785вҶ’        sendbuf[sb_idx] =
   786вҶ’            BufArray1D<Real>(bufs, std::make_pair(buf_offset, buf_offset + bsf2c));
   787вҶ’        buf_offset += bsf2c;
   788вҶ’        PrepareSendFineToCoarseAMR(pb.get(), sendbuf[sb_idx]);
   789вҶ’        int ox1 = ((oloc.lx1 & 1LL) == 1LL), ox2 = ((oloc.lx2 & 1LL) == 1LL),
   790вҶ’            ox3 = ((oloc.lx3 & 1LL) == 1LL);
   791вҶ’        int nn_lid = GetLid(rblist, newrank, nn);
   792вҶ’        tags[sb_idx] = CreateAMRMPITag(nn_lid, ox1, ox2, ox3);
   793вҶ’        dest[sb_idx] = newrank[nn];
   794вҶ’        count[sb_idx] = bsf2c;
   795вҶ’        sb_idx++;
   796вҶ’      }
   797вҶ’    }
   798вҶ’    // wait until all send buffers are filled
   799вҶ’    Kokkos::fence();
   800вҶ’    Kokkos::Profiling::popRegion(); // Step 7a: Pack buffers
   801вҶ’                                    //
   802вҶ’    Kokkos::Profiling::pushRegion("Step 7b: MPI_Isend");
   803вҶ’    for (auto idx = 0; idx < sb_idx; idx++) {
   804вҶ’      PARTHENON_MPI_CHECK(MPI_Isend(sendbuf[idx].data(), count[idx], MPI_PARTHENON_REAL,
   805вҶ’                                    dest[idx], tags[idx], MPI_COMM_WORLD,
