   982вҶ’// AMR: step 6, branch 1 (same2same: just pack+send)
   983вҶ’
   984вҶ’void Mesh::PrepareSendSameLevel(MeshBlock *pmb, BufArray1D<Real> &sendbuf) {
   985вҶ’  // inital offset, data starts after allocation flags
   986вҶ’  int p = pmb->vars_cc_.size();
   987вҶ’
   988вҶ’  // subview to set allocation flags
   989вҶ’  auto alloc_subview = Kokkos::subview(sendbuf, std::make_pair(0, p));
   990вҶ’  auto alloc_subview_h = Kokkos::create_mirror_view(HostMemSpace(), alloc_subview);
   991вҶ’
   992вҶ’  const IndexDomain interior = IndexDomain::interior;
   993вҶ’  IndexRange ib = pmb->cellbounds.GetBoundsI(interior);
   994вҶ’  IndexRange jb = pmb->cellbounds.GetBoundsJ(interior);
   995вҶ’  IndexRange kb = pmb->cellbounds.GetBoundsK(interior);
   996вҶ’  // this helper fn is used for AMR and non-refinement load balancing of
   997вҶ’  // MeshBlocks. Therefore, unlike PrepareSendCoarseToFineAMR(), etc., it loops over
   998вҶ’  // MeshBlock::vars_cc/fc_ containers, not MeshRefinement::pvars_cc/fc_ containers
   999вҶ’
  1000вҶ’  // TODO(felker): add explicit check to ensure that elements of pmb->vars_cc/fc_ and
  1001вҶ’  // pmb->pmr->pvars_cc/fc_ v point to the same objects, if adaptive
  1002вҶ’
  1003вҶ’  // (C++11) range-based for loop: (automatic type deduction fails when iterating over
  1004вҶ’  // container with std::reference_wrapper; could use auto var_cc_r = var_cc.get())
  1005вҶ’  for (int i = 0; i < pmb->vars_cc_.size(); ++i) {
  1006вҶ’    auto &pvar_cc = pmb->vars_cc_[i];
  1007вҶ’    alloc_subview_h(i) = pvar_cc->IsAllocated() ? 1.0 : 0.0;
  1008вҶ’    int nu = pvar_cc->GetDim(4) - 1;
  1009вҶ’    if (pvar_cc->IsAllocated()) {
  1010вҶ’      ParArray4D<Real> var_cc = pvar_cc->data.Get<4>();
  1011вҶ’      BufferUtility::PackData(var_cc, sendbuf, 0, nu, ib.s, ib.e, jb.s, jb.e, kb.s, kb.e,
  1012вҶ’                              p, pmb);
  1013вҶ’    } else {
  1014вҶ’      // increment offset
  1015вҶ’      p += (nu + 1) * (ib.e + 1 - ib.s) * (jb.e + 1 - jb.s) * (kb.e + 1 - kb.s);
  1016вҶ’    }
  1017вҶ’  }
  1018вҶ’
  1019вҶ’  Kokkos::deep_copy(alloc_subview, alloc_subview_h);
  1020вҶ’
  1021вҶ’  // WARNING(felker): casting from "Real *" to "int *" in order to append single integer
  1022вҶ’  // to send buffer is slightly unsafe (especially if sizeof(int) > sizeof(Real))
  1023вҶ’  if (adaptive) {
  1024вҶ’    Kokkos::deep_copy(pmb->exec_space,
  1025вҶ’                      Kokkos::View<int, Kokkos::MemoryUnmanaged>(
  1026вҶ’                          reinterpret_cast<int *>(Kokkos::subview(sendbuf, p).data())),
  1027вҶ’                      pmb->pmr->deref_count_);
  1028вҶ’  }
  1029вҶ’  return;
  1030вҶ’}
