  1032вҶ’// step 6, branch 2 (c2f: just pack+send)
  1033вҶ’
  1034вҶ’void Mesh::PrepareSendCoarseToFineAMR(MeshBlock *pb, BufArray1D<Real> &sendbuf,
  1035вҶ’                                      LogicalLocation &lloc) {
  1036вҶ’  const int f2 = (ndim >= 2) ? 1 : 0; // extra cells/faces from being 2d
  1037вҶ’  const int f3 = (ndim >= 3) ? 1 : 0; // extra cells/faces from being 3d
  1038вҶ’  int ox1 = static_cast<int>((lloc.lx1 & 1LL) == 1LL);
  1039вҶ’  int ox2 = static_cast<int>((lloc.lx2 & 1LL) == 1LL);
  1040вҶ’  int ox3 = static_cast<int>((lloc.lx3 & 1LL) == 1LL);
  1041вҶ’  const IndexDomain interior = IndexDomain::interior;
  1042вҶ’  // pack
  1043вҶ’  int il, iu, jl, ju, kl, ku;
  1044вҶ’  if (ox1 == 0) {
  1045вҶ’    il = pb->cellbounds.is(interior) - 1;
  1046вҶ’    iu = pb->cellbounds.is(interior) + pb->block_size.nx1 / 2;
  1047вҶ’  } else {
  1048вҶ’    il = pb->cellbounds.is(interior) + pb->block_size.nx1 / 2 - 1;
  1049вҶ’    iu = pb->cellbounds.ie(interior) + 1;
  1050вҶ’  }
  1051вҶ’  if (ox2 == 0) {
  1052вҶ’    jl = pb->cellbounds.js(interior) - f2;
  1053вҶ’    ju = pb->cellbounds.js(interior) + pb->block_size.nx2 / 2;
  1054вҶ’  } else {
  1055вҶ’    jl = pb->cellbounds.js(interior) + pb->block_size.nx2 / 2 - f2;
  1056вҶ’    ju = pb->cellbounds.je(interior) + f2;
  1057вҶ’  }
  1058вҶ’  if (ox3 == 0) {
  1059вҶ’    kl = pb->cellbounds.ks(interior) - f3;
  1060вҶ’    ku = pb->cellbounds.ks(interior) + pb->block_size.nx3 / 2;
  1061вҶ’  } else {
  1062вҶ’    kl = pb->cellbounds.ks(interior) + pb->block_size.nx3 / 2 - f3;
  1063вҶ’    ku = pb->cellbounds.ke(interior) + f3;
  1064вҶ’  }
  1065вҶ’
  1066вҶ’  // inital offset, data starts after allocation flags
  1067вҶ’  int p = pb->pmr->pvars_cc_.size();
  1068вҶ’
  1069вҶ’  // subview to set allocation flags
  1070вҶ’  auto alloc_subview = Kokkos::subview(sendbuf, std::make_pair(0, p));
  1071вҶ’  auto alloc_subview_h = Kokkos::create_mirror_view(HostMemSpace(), alloc_subview);
  1072вҶ’
  1073вҶ’  int i = 0;
  1074вҶ’  for (auto &cc_var : pb->pmr->pvars_cc_) {
  1075вҶ’    alloc_subview_h(i) = cc_var->IsAllocated() ? 1.0 : 0.0;
  1076вҶ’    int nu = cc_var->GetDim(4) - 1; // TODO(JMM): looks like this only supports vectors?
  1077вҶ’    if (cc_var->IsAllocated()) {
  1078вҶ’      ParArray4D<Real> var_cc = cc_var->data.Get<4>();
  1079вҶ’      BufferUtility::PackData(var_cc, sendbuf, 0, nu, il, iu, jl, ju, kl, ku, p, pb);
  1080вҶ’    } else {
  1081вҶ’      BufferUtility::PackZero(sendbuf, 0, nu, il, iu, jl, ju, kl, ku, p, pb);
  1082вҶ’    }
  1083вҶ’    i++;
  1084вҶ’  }
  1085вҶ’
  1086вҶ’  Kokkos::deep_copy(alloc_subview, alloc_subview_h);
  1087вҶ’
  1088вҶ’  return;
  1089вҶ’}
