  1091вҶ’// step 6, branch 3 (f2c: restrict, pack, send)
  1092вҶ’
  1093вҶ’void Mesh::PrepareSendFineToCoarseAMR(MeshBlock *pb, BufArray1D<Real> &sendbuf) {
  1094вҶ’  // restrict and pack
  1095вҶ’
  1096вҶ’  const IndexDomain interior = IndexDomain::interior;
  1097вҶ’  IndexRange cib = pb->c_cellbounds.GetBoundsI(interior);
  1098вҶ’  IndexRange cjb = pb->c_cellbounds.GetBoundsJ(interior);
  1099вҶ’  IndexRange ckb = pb->c_cellbounds.GetBoundsK(interior);
  1100вҶ’
  1101вҶ’  auto &pmr = pb->pmr;
  1102вҶ’
  1103вҶ’  // inital offset, data starts after allocation flags
  1104вҶ’  int p = pmr->pvars_cc_.size();
  1105вҶ’
  1106вҶ’  // subview to set allocation flags
  1107вҶ’  auto alloc_subview = Kokkos::subview(sendbuf, std::make_pair(0, p));
  1108вҶ’  auto alloc_subview_h = Kokkos::create_mirror_view(HostMemSpace(), alloc_subview);
  1109вҶ’
  1110вҶ’  int i = 0;
  1111вҶ’  for (auto &cc_var : pmr->pvars_cc_) {
  1112вҶ’    alloc_subview_h(i) = cc_var->IsAllocated() ? 1.0 : 0.0;
  1113вҶ’    int nu = cc_var->GetDim(4) - 1;
  1114вҶ’    if (cc_var->IsAllocated()) {
  1115вҶ’      pmr->RestrictCellCenteredValues(cc_var.get(), cib.s, cib.e, cjb.s, cjb.e, ckb.s,
  1116вҶ’                                      ckb.e);
  1117вҶ’      // TOGO(pgrete) remove temp var once Restrict func interface is updated
  1118вҶ’      ParArray4D<Real> coarse_cc = (cc_var->coarse_s).Get<4>();
  1119вҶ’      BufferUtility::PackData(coarse_cc, sendbuf, 0, nu, cib.s, cib.e, cjb.s, cjb.e,
  1120вҶ’                              ckb.s, ckb.e, p, pb);
  1121вҶ’    } else {
  1122вҶ’      BufferUtility::PackZero(sendbuf, 0, nu, cib.s, cib.e, cjb.s, cjb.e, ckb.s, ckb.e, p,
  1123вҶ’                              pb);
  1124вҶ’    }
  1125вҶ’    i++;
  1126вҶ’  }
  1127вҶ’
  1128вҶ’  Kokkos::deep_copy(alloc_subview, alloc_subview_h);
  1129вҶ’
  1130вҶ’  return;
  1131вҶ’}
