  1133вҶ’// step 7: f2c, same MPI rank, different level (just restrict+copy, no pack/send)
  1134вҶ’
  1135вҶ’void Mesh::FillSameRankFineToCoarseAMR(MeshBlock *pob, MeshBlock *pmb,
  1136вҶ’                                       LogicalLocation &loc) {
  1137вҶ’  auto &pmr = pob->pmr;
  1138вҶ’  const IndexDomain interior = IndexDomain::interior;
  1139вҶ’  int il =
  1140вҶ’      pmb->cellbounds.is(interior) + ((loc.lx1 & 1LL) == 1LL) * pmb->block_size.nx1 / 2;
  1141вҶ’  int jl =
  1142вҶ’      pmb->cellbounds.js(interior) + ((loc.lx2 & 1LL) == 1LL) * pmb->block_size.nx2 / 2;
  1143вҶ’  int kl =
  1144вҶ’      pmb->cellbounds.ks(interior) + ((loc.lx3 & 1LL) == 1LL) * pmb->block_size.nx3 / 2;
  1145вҶ’
  1146вҶ’  IndexRange cib = pob->c_cellbounds.GetBoundsI(interior);
  1147вҶ’  IndexRange cjb = pob->c_cellbounds.GetBoundsJ(interior);
  1148вҶ’  IndexRange ckb = pob->c_cellbounds.GetBoundsK(interior);
  1149вҶ’  // absent a zip() feature for range-based for loops, manually advance the
  1150вҶ’  // iterator over "SMR/AMR-enrolled" cell-centered quantities on the new
  1151вҶ’  // MeshBlock in lock-step with pob
  1152вҶ’  auto pmb_cc_it = pmb->pmr->pvars_cc_.begin();
  1153вҶ’  // iterate MeshRefinement std::vectors on pob
  1154вҶ’  for (auto cc_var : pmr->pvars_cc_) {
  1155вҶ’    const bool fine_allocated = cc_var->IsAllocated();
  1156вҶ’    if (!(*pmb_cc_it)->IsAllocated()) {
  1157вҶ’      PARTHENON_REQUIRE_THROWS(!fine_allocated,
  1158вҶ’                               "Mesh::FillSameRankFineToCoarseAMR: Destination not "
  1159вҶ’                               "allocated but source allocated");
  1160вҶ’      pmb_cc_it++;
  1161вҶ’      continue;
  1162вҶ’    }
  1163вҶ’    if (fine_allocated) {
  1164вҶ’      pmr->RestrictCellCenteredValues(cc_var.get(), cib.s, cib.e, cjb.s, cjb.e, ckb.s,
  1165вҶ’                                      ckb.e);
  1166вҶ’    }
  1167вҶ’
  1168вҶ’    // copy from old/original/other MeshBlock (pob) to newly created block (pmb)
  1169вҶ’    ParArrayND<Real> src = cc_var->coarse_s;
  1170вҶ’    ParArrayND<Real> dst = (*pmb_cc_it)->data;
  1171вҶ’    int nu = cc_var->GetDim(4) - 1;
  1172вҶ’    int koff = kl - ckb.s;
  1173вҶ’    int joff = jl - cjb.s;
  1174вҶ’    int ioff = il - cib.s;
  1175вҶ’    pmb->par_for(
  1176вҶ’        "FillSameRankFineToCoarseAMR", 0, nu, ckb.s, ckb.e, cjb.s, cjb.e, cib.s, cib.e,
  1177вҶ’        KOKKOS_LAMBDA(const int nv, const int k, const int j, const int i) {
  1178вҶ’          // if the destination (coarse) is allocated, but source (fine) is not allocated,
  1179вҶ’          // we just fill destination with 0's
  1180вҶ’          dst(nv, k + koff, j + joff, i + ioff) = fine_allocated ? src(nv, k, j, i) : 0.0;
  1181вҶ’        });
  1182вҶ’    pmb_cc_it++;
  1183вҶ’  }
  1184вҶ’
  1185вҶ’  return;
  1186вҶ’}
  1187вҶ’
  1188вҶ’// step 7: c2f, same MPI rank, different level (just copy+prolongate, no pack/send)
  1189вҶ’
  1190вҶ’void Mesh::FillSameRankCoarseToFineAMR(MeshBlock *pob, MeshBlock *pmb,
  1191вҶ’                                       LogicalLocation &newloc) {
  1192вҶ’  auto &pmr = pmb->pmr;
  1193вҶ’
