  1419вҶ’
  1420вҶ’int Mesh::CreateAMRMPITag(int lid, int ox1, int ox2, int ox3) {
  1421вҶ’  // the trailing zero is used as "id" to indicate an AMR related tag
  1422вҶ’  return (lid << 8) | (ox1 << 7) | (ox2 << 6) | (ox3 << 5) | 0;
